    captured_cwd: list[str | None] = []

    def _capturing_subprocess(cmd, timeout, cwd=None):
        captured_cwd.append(cwd)
        return {"stdout": "ok", "stderr": "", "return_code": 0,
                "timed_out": False, "execution_status": "success", "capture_status": "complete"}

